class ModernCarousel {
constructor(options) {
this.containerId = options.containerId;
this.container = document.getElementById(this.containerId);
this.items = options.items || [];
this.prevBtnId = options.prevBtnId;
this.nextBtnId = options.nextBtnId;
this.currentIndex = 0;
this.autoRotate = options.autoRotate || false;
this.autoRotateInterval = options.autoRotateInterval || 5000;
this.intervalId = null;
this.touchStartX = 0;
this.touchEndX = 0;
if (this.container) {
this.init();
} else {
}
}
getItemsPerView() {
const width = window.innerWidth;
if (width < 768) return 1;
if (width < 1024) return 2;
return 3;
}
init() {
this.render();
this.setupNavigation();
this.setupTouchGestures();
this.setupResizeHandler();
if (this.autoRotate && this.items.length > this.getItemsPerView()) {
this.startAutoRotate();
}
}
render() {
if (!this.container) return;
this.container.innerHTML = '';
this.items.forEach((item, index) => {
const element = this.createItemElement(item, index);
this.container.appendChild(element);
});
this.updatePosition(false);
if (window.UroUtils && window.UroUtils.replaceFeatherIcons) {
window.UroUtils.replaceFeatherIcons();
} else if (typeof feather !== 'undefined') {
feather.replace();
}
}
createItemElement(item, index) {
const div = document.createElement('div');
div.className = 'carousel-item flex-shrink-0 px-3';
div.setAttribute('data-index', index);
const gradientClass = item.type === 'protocol'
? 'from-uro-azul to-uro-azul_claro'
: 'from-uro-azul_escuro to-uro-azul';
const iconType = item.type === 'protocol' ? 'file-text' : 'book-open';
const linkText = item.type === 'protocol' ? 'Ver Protocolo' : 'Ler Artigo';
div.innerHTML = `
<div class="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-xl transition-all duration-300 h-full card-hover">
<div class="h-40 bg-gradient-to-r ${gradientClass} flex items-center justify-center relative overflow-hidden">
<div class="absolute inset-0 bg-white opacity-0 hover:opacity-10 transition-opacity"></div>
<i data-feather="${iconType}" class="w-12 h-12 text-white relative z-10" aria-hidden="true"></i>
</div>
<div class="p-6">
<h3 class="text-xl font-bold text-uro-azul_escuro mb-3 line-clamp-2 min-h-[3.5rem]">${item.title}</h3>
<p class="text-gray-600 text-sm mb-4 line-clamp-3 min-h-[4.5rem]">${item.description}</p>
<div class="flex justify-between items-center pt-2 border-t border-gray-100">
<span class="text-xs text-gray-500 flex items-center">
<i data-feather="calendar" class="w-3 h-3 mr-1" aria-hidden="true"></i>
${item.date}
</span>
<a href="${item.url}"
class="inline-flex items-center text-uro-azul font-medium hover:text-uro-azul_escuro transition-colors text-sm group">
${linkText}
<i data-feather="arrow-right" class="w-4 h-4 ml-1 transform group-hover:translate-x-1 transition-transform" aria-hidden="true"></i>
</a>
</div>
</div>
</div>
`;
return div;
}
setupNavigation() {
const prevBtn = document.getElementById(this.prevBtnId);
const nextBtn = document.getElementById(this.nextBtnId);
if (!prevBtn || !nextBtn) {
return;
}
const itemsPerView = this.getItemsPerView();
if (this.items.length <= itemsPerView) {
prevBtn.style.display = 'none';
nextBtn.style.display = 'none';
return;
}
prevBtn.style.display = 'flex';
nextBtn.style.display = 'flex';
prevBtn.addEventListener('click', (e) => {
e.preventDefault();
this.prev();
this.resetAutoRotate();
});
nextBtn.addEventListener('click', (e) => {
e.preventDefault();
this.next();
this.resetAutoRotate();
});
this.updateButtonStates();
}
updateButtonStates() {
const prevBtn = document.getElementById(this.prevBtnId);
const nextBtn = document.getElementById(this.nextBtnId);
if (!prevBtn || !nextBtn) return;
const itemsPerView = this.getItemsPerView();
const maxIndex = Math.max(0, this.items.length - itemsPerView);
if (this.currentIndex === 0) {
prevBtn.classList.add('opacity-50', 'cursor-not-allowed');
prevBtn.disabled = true;
} else {
prevBtn.classList.remove('opacity-50', 'cursor-not-allowed');
prevBtn.disabled = false;
}
if (this.currentIndex >= maxIndex) {
nextBtn.classList.add('opacity-50', 'cursor-not-allowed');
nextBtn.disabled = true;
} else {
nextBtn.classList.remove('opacity-50', 'cursor-not-allowed');
nextBtn.disabled = false;
}
}
setupTouchGestures() {
if (!this.container) return;
this.container.addEventListener('touchstart', (e) => {
this.touchStartX = e.changedTouches[0].screenX;
}, { passive: true });
this.container.addEventListener('touchend', (e) => {
this.touchEndX = e.changedTouches[0].screenX;
this.handleSwipe();
}, { passive: true });
}
handleSwipe() {
const swipeThreshold = 50;
const diff = this.touchStartX - this.touchEndX;
if (Math.abs(diff) < swipeThreshold) return;
if (diff > 0) {
this.next();
} else {
this.prev();
}
this.resetAutoRotate();
}
setupResizeHandler() {
let resizeTimeout;
window.addEventListener('resize', () => {
clearTimeout(resizeTimeout);
resizeTimeout = setTimeout(() => {
this.updatePosition(false);
this.updateButtonStates();
}, 100);
});
}
prev() {
if (this.currentIndex > 0) {
this.currentIndex--;
this.updatePosition();
this.updateButtonStates();
}
}
next() {
const itemsPerView = this.getItemsPerView();
const maxIndex = Math.max(0, this.items.length - itemsPerView);
if (this.currentIndex < maxIndex) {
this.currentIndex++;
this.updatePosition();
this.updateButtonStates();
} else if (this.autoRotate) {
this.currentIndex = 0;
this.updatePosition();
this.updateButtonStates();
}
}
updatePosition(animate = true) {
if (!this.container) return;
const itemsPerView = this.getItemsPerView();
const itemWidth = 100 / itemsPerView;
const translateX = -this.currentIndex * itemWidth;
if (animate) {
this.container.style.transition = 'transform 0.5s cubic-bezier(0.4, 0, 0.2, 1)';
} else {
this.container.style.transition = 'none';
}
this.container.style.transform = `translateX(${translateX}%)`;
if (!animate) {
void this.container.offsetWidth;
}
}
startAutoRotate() {
if (this.intervalId) return;
this.intervalId = setInterval(() => {
this.next();
}, this.autoRotateInterval);
}
stopAutoRotate() {
if (this.intervalId) {
clearInterval(this.intervalId);
this.intervalId = null;
}
}
resetAutoRotate() {
if (this.autoRotate) {
this.stopAutoRotate();
this.startAutoRotate();
}
}
destroy() {
this.stopAutoRotate();
if (this.container) {
this.container.innerHTML = '';
}
}
}
let protocolos = [];
let artigos = [];
let protocolCarousel = null;
let articleCarousel = null;
async function carregarDados() {
try {
const [protocolosRaw, artigosRaw] = await Promise.all([
fetch('assets/data/protocolos.json').then(r => r.json()),
fetch('assets/data/artigos.json').then(r => r.json())
]);
const protocolosData = Array.isArray(protocolosRaw) ? protocolosRaw : (protocolosRaw.items || []);
const artigosData = Array.isArray(artigosRaw) ? artigosRaw : (artigosRaw.items || []);
protocolos = protocolosData.map(p => ({
type: 'protocol',
title: p.titulo,
description: p.descricao,
date: `Atualizado: ${p.data}`,
url: `pages/protocolo/${p.arquivo}`
}));
artigos = artigosData.map(a => ({
type: 'article',
title: a.titulo,
description: a.descricao,
date: `Publicado: ${a.data}`,
url: `pages/artigo/${a.arquivo}`
}));
} catch (error) {
protocolos = [
{
type: 'protocol',
title: 'Infecção do Trato Urinário',
description: 'Diretrizes atualizadas baseadas no Protocolo FEBRASGO nº 48 para diagnóstico e tratamento da ITU em mulheres.',
date: 'Atualizado: Jan/2025',
url: 'pages/protocolo/infeccao-do-trato-urinario.html'
},
{
type: 'protocol',
title: 'Incontinência Urinária de Esforço',
description: 'Abordagem baseada em evidências para diagnóstico e tratamento da incontinência urinária de esforço.',
date: 'Atualizado: Jan/2025',
url: 'pages/protocolo/incontinencia-urinaria-esforco.html'
},
{
type: 'protocol',
title: 'Síndrome Bexiga Hiperativa',
description: 'Protocolo completo para diagnóstico e tratamento da bexiga hiperativa em mulheres.',
date: 'Atualizado: Jan/2025',
url: 'pages/protocolo/sindrome-bexiga-hiperativa.html'
},
{
type: 'protocol',
title: 'Incontinência Urinária Não Especificada',
description: 'Protocolo para abordagem de casos complexos de incontinência urinária.',
date: 'Atualizado: Fev/2025',
url: 'pages/protocolo/incontinencia-urinaria-nao.html'
}
];
artigos = [
{
type: 'article',
title: 'Eficácia da Toxina Botulínica na Bexiga Hiperativa',
description: 'Meta-análise de ensaios clínicos randomizados avaliando a eficácia e segurança da toxina botulínica no tratamento da bexiga hiperativa refratária.',
date: 'Publicado: 15/01/2025',
url: 'pages/artigo/acupuntura-urinaria-feminina.html'
},
{
type: 'article',
title: 'Impacto da Menopausa na Função do Assoalho Pélvico',
description: 'Estudo longitudinal avaliando alterações na função do assoalho pélvico durante a transição menopausal e estratégias de prevenção.',
date: 'Publicado: 10/01/2025',
url: 'pages/artigo/cirurgias-incontinencia.html'
},
{
type: 'article',
title: 'Terapias Comportamentais para Incontinência Urinária',
description: 'Revisão sistemática sobre a eficácia de intervenções comportamentais no tratamento da incontinência urinária de esforço.',
date: 'Publicado: 08/01/2025',
url: 'pages/artigo/revi-literaria-artigo.html'
},
{
type: 'article',
title: 'Novos Fármacos para Bexiga Hiperativa',
description: 'Revisão sistemática avaliando a eficácia e segurança de novos agentes farmacológicos no tratamento da síndrome da bexiga hiperativa.',
date: 'Publicado: 05/01/2025',
url: 'pages/artigo/revisao-ssistematica.html'
},
{
type: 'article',
title: 'Cirurgia Robótica em Prolapso Genital',
description: 'Análise comparativa entre abordagens robóticas e tradicionais no tratamento do prolapso genital avançado.',
date: 'Publicado: 03/01/2025',
url: 'pages/artigo/urinaria-atencao-basica.html'
}
];
}
}
document.addEventListener('DOMContentLoaded', async function() {
await carregarDados();
protocolCarousel = new ModernCarousel({
containerId: 'protocolsCarousel',
items: protocolos,
prevBtnId: 'prevProtocol',
nextBtnId: 'nextProtocol',
autoRotate: false,
autoRotateInterval: 5000
});
articleCarousel = new ModernCarousel({
containerId: 'articlesCarousel',
items: artigos,
prevBtnId: 'prevArticle',
nextBtnId: 'nextArticle',
autoRotate: false,
autoRotateInterval: 5000
});
if (window.UroUtils && window.UroUtils.replaceFeatherIcons) {
window.UroUtils.replaceFeatherIcons();
} else if (typeof feather !== 'undefined') {
feather.replace();
}
});